mapper.update:
update user_course set status = 1
where cid = #{cid}
and uid = #{uid}

mapper.select:
select sum(e.score) from exam e,answer a
where a.username = #{username}
and e.question_id = a.question_id
and e.answer = a.answer
and e.subject = #{subject}

select e.question_id,e.content,e.score,e.type,e.options,e.subject from user u,exam e
where u.username = #{username}
and e.subject = #{subject}
